log_step "Initialize and create test data"
br init --prefix test
ORPHAN_ID=$(br create "Orphan issue" --silent)
EPIC_ID=$(br create "Test Epic" --type epic --silent)
CHILD_ID=$(br create "Child issue" --parent "$EPIC_ID" --silent)

log_step "Testing orphans detection"
ORPHANS_OUTPUT=$(br orphans)
log_debug "Orphans output: $ORPHANS_OUTPUT"
if echo "$ORPHANS_OUTPUT" | grep -q "$ORPHAN_ID"; then
    log_pass "Orphan issue detected"
else
    log_fail "Orphan issue not found"
    exit 1
fi

log_step "Verifying child not in orphans"
if echo "$ORPHANS_OUTPUT" | grep -q "$CHILD_ID"; then
    log_fail "Child issue incorrectly marked as orphan"
    exit 1
else
    log_pass "Child issue correctly excluded"
fi

log_step "Testing JSON output"
ORPHANS_JSON=$(br orphans --json)
log_debug "JSON: $ORPHANS_JSON"
echo "$ORPHANS_JSON" | jq -e '.'
log_pass "Orphans JSON valid"

log_pass "=== All orphans tests passed ==="
